import{_ as a,a as e,b as d,c as l}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as s,o,c as n,a2 as i}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"S3 渠道添加说明","description":"","frontmatter":{},"headers":[],"relativePath":"cn/upload/s3.md","filePath":"cn/upload/s3.md","lastUpdated":1781962217000}'),c={name:"cn/upload/s3.md"};function r(p,t,h,u,b,g){return o(),n("div",null,[...t[0]||(t[0]=[i(`<h1 id="s3-渠道添加说明" tabindex="-1">S3 渠道添加说明 <a class="header-anchor" href="#s3-渠道添加说明" aria-label="Permalink to &quot;S3 渠道添加说明&quot;">​</a></h1><h2 id="适合什么场景" tabindex="-1">适合什么场景 <a class="header-anchor" href="#适合什么场景" aria-label="Permalink to &quot;适合什么场景&quot;">​</a></h2><ul><li>你要接入支持 S3 协议的对象存储，例如 Cloudflare R2、Backblaze B2、MinIO、AWS S3 或其他兼容服务。</li><li>你希望用 <code>Endpoint</code>、Access Key、Secret Key 这一套标准 S3 参数来上传文件。</li><li>你不想使用 Cloudflare 原生 R2 绑定渠道，或者你的存储服务本身不是 Cloudflare R2 绑定。</li></ul><h2 id="添加前要准备什么" tabindex="-1">添加前要准备什么 <a class="header-anchor" href="#添加前要准备什么" aria-label="Permalink to &quot;添加前要准备什么&quot;">​</a></h2><table tabindex="0"><thead><tr><th>需要准备</th><th>用途</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>对象存储的 S3 API 地址</td></tr><tr><td>Bucket 名称</td><td>文件实际保存的桶</td></tr><tr><td>Region</td><td>存储区域；Cloudflare R2 通常填 <code>auto</code></td></tr><tr><td>Access Key ID</td><td>S3 访问密钥 ID</td></tr><tr><td>Secret Access Key</td><td>S3 机密访问密钥</td></tr><tr><td>CDN 域名</td><td>可选，用于自定义文件访问域名</td></tr></tbody></table><p>以 Cloudflare R2 的 S3 API 为例：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://你的AccountID.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: 你的R2桶名</span></span>
<span class="line"><span>Region: auto</span></span>
<span class="line"><span>Access Key ID: 从 Cloudflare R2 API Token 里复制</span></span>
<span class="line"><span>Secret Access Key: 从 Cloudflare R2 API Token 里复制</span></span></code></pre></div><h2 id="入口位置" tabindex="-1">入口位置 <a class="header-anchor" href="#入口位置" aria-label="Permalink to &quot;入口位置&quot;">​</a></h2><ol><li>进入系统配置。</li><li>打开上传设置。</li><li>点击右上角“添加渠道”。</li><li>选择 <code>S3</code>。</li></ol><h2 id="字段说明" tabindex="-1">字段说明 <a class="header-anchor" href="#字段说明" aria-label="Permalink to &quot;字段说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>作用</th><th>是否必填</th></tr></thead><tbody><tr><td>渠道名称</td><td>用来区分当前 S3 渠道，例如 <code>s3test</code>、<code>R2-S3</code></td><td>是</td></tr><tr><td>启用渠道</td><td>控制这个渠道是否参与上传选择</td><td>建议开启</td></tr><tr><td>Endpoint</td><td>S3 服务地址，需要填写完整 <code>https://</code> 地址</td><td>是</td></tr><tr><td>自定义 CDN 域名</td><td>可选。填写后，读取文件时优先按这个域名生成访问地址</td><td>否</td></tr><tr><td>存储桶名称</td><td>Bucket 名称，例如 <code>s3test</code>、<code>img-r2</code></td><td>是</td></tr><tr><td>存储桶区域</td><td>Region。Cloudflare R2 通常填 <code>auto</code></td><td>是</td></tr><tr><td>访问密钥 ID</td><td>Access Key ID</td><td>是</td></tr><tr><td>机密访问密钥</td><td>Secret Access Key</td><td>是</td></tr><tr><td>路径风格</td><td>兼容开关，默认关闭；部分 MinIO、OpenList 或自建 S3 服务可能需要开启</td><td>否</td></tr><tr><td>容量限制</td><td>控制这个 S3 渠道是否按容量阈值参与上传选择</td><td>否</td></tr><tr><td>容量上限</td><td>开启容量限制后填写，例如 <code>10 GB</code></td><td>开启容量限制时填写</td></tr><tr><td>阈值</td><td>达到多少比例后不再继续写入，例如 <code>90%</code></td><td>开启容量限制时填写</td></tr><tr><td>备注</td><td>方便自己记录用途</td><td>否</td></tr></tbody></table><h2 id="用-cloudflare-r2-的-s3-api-创建密钥" tabindex="-1">用 Cloudflare R2 的 S3 API 创建密钥 <a class="header-anchor" href="#用-cloudflare-r2-的-s3-api-创建密钥" aria-label="Permalink to &quot;用 Cloudflare R2 的 S3 API 创建密钥&quot;">​</a></h2><ol><li>打开 Cloudflare Dashboard。</li><li>进入 <code>R2 Object Storage</code>。</li><li>找到 <code>Manage R2 API Tokens</code> 或 API Token 管理入口。</li></ol><p>![R2 API Token 入口](../../image/upload/s3/r2 api token入口.png)</p><ol start="4"><li>创建一个允许访问目标 Bucket 的 R2 API Token。</li></ol><p><img src="`+a+'" alt="创建账户 API 令牌" loading="lazy"></p><ol start="5"><li>复制生成的 <code>Access Key ID</code> 和 <code>Secret Access Key</code>。</li></ol><p><img src="'+e+'" alt="复制令牌值" loading="lazy"></p><ol start="6"><li>回到 R2 Bucket 页面，确认 Bucket 名称。</li><li>记录当前账号的 S3 API 地址，格式通常是：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://你的AccountID.r2.cloudflarestorage.com</span></span></code></pre></div><h2 id="添加步骤" tabindex="-1">添加步骤 <a class="header-anchor" href="#添加步骤" aria-label="Permalink to &quot;添加步骤&quot;">​</a></h2><ol><li>打开上传设置页面。</li><li>点击“添加渠道”。</li><li>选择 <code>S3</code>。</li><li>渠道名称填一个自己能看懂的名字，例如 <code>s3test</code>。</li><li><code>Endpoint</code> 填 S3 API 地址。</li><li>如果有自定义 CDN，就填写 <code>自定义 CDN 域名</code>；没有就留空。</li><li><code>存储桶名称</code> 填 Bucket 名称。</li><li><code>存储桶区域</code> 填 Region。Cloudflare R2 示例里填 <code>auto</code>。</li><li>填写 <code>访问密钥 ID</code> 和 <code>机密访问密钥</code>。</li><li><code>路径风格</code> 默认关闭；只有当前服务明确要求 path-style 时再打开。</li><li>如果要控制容量，就打开容量限制，填写容量上限和阈值。</li><li>点击保存。</li></ol><p><img src="'+d+'" alt="添加 S3 配置" loading="lazy"></p><h2 id="添加完成后怎么检查" tabindex="-1">添加完成后怎么检查 <a class="header-anchor" href="#添加完成后怎么检查" aria-label="Permalink to &quot;添加完成后怎么检查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>检查项</th><th>检查方式</th></tr></thead><tbody><tr><td>渠道卡片是否出现</td><td>保存后，上传设置页面应显示 S3 渠道卡片</td></tr><tr><td>渠道是否启用</td><td>卡片右上角开关应保持开启</td></tr><tr><td>关键字段是否保存</td><td>详情页能看到 Endpoint、Bucket、Region、路径风格等信息</td></tr><tr><td>上传是否正常</td><td>上传一张测试图片，确认对象已进入目标 Bucket</td></tr><tr><td>链接是否能打开</td><td>上传返回的图片链接能正常访问</td></tr><tr><td>容量显示是否正常</td><td>开启容量限制后，卡片应显示已用容量和上限</td></tr></tbody></table><p>S3 容量统计不是去对象存储官方接口实时查桶，而是按图床本地文件记录重新计算。保存 S3 配置后，系统会按当前 D1 记录重算一次容量账。</p><p><img src="'+l+`" alt="查询额度成功的卡牌" loading="lazy"></p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="路径风格要不要打开" tabindex="-1">路径风格要不要打开？ <a class="header-anchor" href="#路径风格要不要打开" aria-label="Permalink to &quot;路径风格要不要打开？&quot;">​</a></h3><p>默认不要打开。</p><p>只有当前 S3 兼容服务不支持虚拟主机风格地址，或者服务商文档明确要求 path-style 时再打开。部分 MinIO、自建 S3、OpenList 兼容接口可能需要开启。</p><h3 id="cdn-域名有什么用" tabindex="-1">CDN 域名有什么用？ <a class="header-anchor" href="#cdn-域名有什么用" aria-label="Permalink to &quot;CDN 域名有什么用？&quot;">​</a></h3><p>如果你给 Bucket 前面接了自己的 CDN 或自定义访问域名，可以填这里。</p><p>填写后，系统生成访问链接时会优先使用这个域名。没有 CDN 就留空。</p><h3 id="为什么上传失败" tabindex="-1">为什么上传失败？ <a class="header-anchor" href="#为什么上传失败" aria-label="Permalink to &quot;为什么上传失败？&quot;">​</a></h3><p>优先检查：</p><ol><li>Endpoint 是否完整包含 <code>https://</code>。</li><li>Bucket 名称是否写对。</li><li>Region 是否符合服务商要求。</li><li>Access Key ID 和 Secret Access Key 是否复制完整。</li><li>当前密钥是否有目标 Bucket 的写入权限。</li><li>当前服务是否需要开启路径风格。</li></ol><h2 id="一句话流程速查" tabindex="-1">一句话流程速查 <a class="header-anchor" href="#一句话流程速查" aria-label="Permalink to &quot;一句话流程速查&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>准备 S3 Endpoint、Bucket、Region、Access Key、Secret Key</span></span>
<span class="line"><span>-&gt; 打开上传设置</span></span>
<span class="line"><span>-&gt; 添加渠道</span></span>
<span class="line"><span>-&gt; 选择 S3</span></span>
<span class="line"><span>-&gt; 填写 Endpoint / Bucket / Region / Access Key / Secret Key</span></span>
<span class="line"><span>-&gt; 按需填写 CDN 域名</span></span>
<span class="line"><span>-&gt; 默认关闭路径风格</span></span>
<span class="line"><span>-&gt; 按需开启容量限制</span></span>
<span class="line"><span>-&gt; 保存</span></span>
<span class="line"><span>-&gt; 上传测试图片检查结果</span></span></code></pre></div>`,39)])])}const f=s(c,[["render",r]]);export{m as __pageData,f as default};
